import React, { useState, useEffect } from "react";
import { 
  Layers, Hash, Save, CheckSquare, Square, 
  Loader2, Edit, Trash2, Search, XCircle 
} from "lucide-react";
import axios from "../api/axios"; // Ensure this points to your Port 5004 config
import toast from "react-hot-toast";

const CategoryMaster = () => {
  // State Management
  const [exams, setExams] = useState([]);
  const [categories, setCategories] = useState([]);
  const [loading, setLoading] = useState(true);
  const [isSaving, setIsSaving] = useState(false);
  const [editId, setEditId] = useState(null);
  const [searchTerm, setSearchTerm] = useState("");
  
  const [formData, setFormData] = useState({ 
    catId: "", 
    examId: "", 
    catName: "", 
    features: [] 
  });

  const featureOptions = ["SYLLABUS", "MOCK TEST", "PYQ", "STUDY MATERIAL", "VIDEOS"];

  // 1. Fetch Master Data (Exams, Categories, and Next ID)
  const fetchData = async () => {
    setLoading(true);
    try {
      const [exRes, catRes, idRes] = await Promise.all([
        axios.get("/master/exam/all"),
        axios.get("/master/category/all"),
        axios.get("/master/category/next-id")
      ]);

      if (exRes.data.success) setExams(exRes.data.data);
      if (catRes.data.success) setCategories(catRes.data.data);
      
      // Only auto-set ID if we are NOT in edit mode
      if (idRes.data.success && !editId) {
        setFormData(prev => ({ ...prev, catId: idRes.data.nextId }));
      }
    } catch (err) {
      console.error(err);
      toast.error("DATABASE SYNC FAILED");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  // 2. Handle Feature Checkboxes
  const toggleFeature = (feature) => {
    setFormData(prev => ({
      ...prev,
      features: prev.features.includes(feature)
        ? prev.features.filter(f => f !== feature)
        : [...prev.features, feature]
    }));
  };

  // 3. Handle Create / Update
  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!formData.examId) return toast.error("PLEASE SELECT A PARENT EXAM");
    
    setIsSaving(true);
    try {
      // Logic: Send the editId if it exists to trigger the backend "Update" logic
      const res = await axios.post("/master/category/upsert", {
        id: editId,
        ...formData
      });

      if (res.data.success) {
        toast.success(editId ? "CATEGORY UPDATED" : "CATEGORY SAVED");
        setEditId(null);
        setFormData({ catId: "", examId: "", catName: "", features: [] });
        fetchData(); // Refresh list and generate NEW CAT ID
      }
    } catch (err) {
      toast.error(err.response?.data?.message || "SAVE FAILED");
    } finally {
      setIsSaving(false);
    }
  };

  // 4. Handle Edit Initiation
  const handleEdit = (cat) => {
    setEditId(cat._id);
    setFormData({
      catId: cat.catId,
      examId: cat.examId?._id || "",
      catName: cat.catName,
      features: cat.features || []
    });
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  // 5. Handle Delete
  const handleDelete = async (id) => {
    if (!window.confirm("ARE YOU SURE YOU WANT TO DELETE THIS CATEGORY?")) return;
    try {
      const res = await axios.delete(`/master/category/${id}`);
      if (res.data.success) {
        toast.success("DELETED SUCCESSFULLY");
        fetchData();
      }
    } catch (err) {
      toast.error("DELETE FAILED");
    }
  };

  // 6. Search Filter Logic
  const filteredCategories = categories.filter(c => 
    c.catName.toLowerCase().includes(searchTerm.toLowerCase()) ||
    c.examId?.examName.toLowerCase().includes(searchTerm.toLowerCase()) ||
    c.catId.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="p-6 max-w-7xl mx-auto space-y-10 font-sans">
      
      {/* --- FORM CARD --- */}
      <section className="bg-white rounded-[40px] p-8 md:p-12 shadow-2xl shadow-slate-200 border border-slate-100 transition-all">
        <header className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 mb-10">
          <div className="flex items-center gap-4">
            <div className="p-4 bg-blue-600 rounded-[22px] text-white shadow-lg shadow-blue-100">
              <Layers size={24} />
            </div>
            <div>
              <h1 className="text-3xl font-black text-slate-900 uppercase tracking-tighter">
                {editId ? "Edit Category" : "Category Master"}
              </h1>
              <p className="text-[10px] font-bold text-slate-400 uppercase tracking-[0.3em]">Setup Sub-Exams & Features</p>
            </div>
          </div>
          {editId && (
            <button 
              onClick={() => { setEditId(null); setFormData({ catId: "", examId: "", catName: "", features: [] }); fetchData(); }}
              className="flex items-center gap-2 text-red-500 font-black text-[10px] uppercase hover:bg-red-50 px-4 py-2 rounded-xl transition-all"
            >
              <XCircle size={14} /> Cancel Edit
            </button>
          )}
        </header>

        <form onSubmit={handleSubmit} className="space-y-10">
          <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
            {/* Category ID (Auto-Generated) */}
            <div>
              <label className="text-[10px] font-black uppercase text-slate-500 tracking-widest mb-3 block">Category ID Code</label>
              <div className="flex items-center gap-3 p-4 bg-slate-50 border-2 border-slate-100 rounded-2xl font-black text-blue-600 text-lg">
                <Hash size={18} /> {formData.catId || "---"}
              </div>
            </div>

            {/* Parent Exam Selection */}
            <div>
              <label className="text-[10px] font-black uppercase text-slate-500 tracking-widest mb-3 block">Select Parent Exam</label>
              <select 
                required
                className="w-full p-4 bg-white border-2 border-slate-100 rounded-2xl font-black text-sm outline-none focus:border-blue-600 focus:ring-4 focus:ring-blue-50 transition-all uppercase"
                value={formData.examId}
                onChange={(e) => setFormData({...formData, examId: e.target.value})}
              >
                <option value="">-- CHOOSE EXAM --</option>
                {exams.map(ex => (
                  <option key={ex._id} value={ex._id}>{ex.examName}</option>
                ))}
              </select>
            </div>

            {/* Category Name */}
            <div>
              <label className="text-[10px] font-black uppercase text-slate-500 tracking-widest mb-3 block">Category Name</label>
              <input 
                required
                type="text"
                placeholder="e.g. NTPC, CGL, WBPSC"
                className="w-full p-4 bg-white border-2 border-slate-100 rounded-2xl font-black text-sm outline-none focus:border-blue-600 focus:ring-4 focus:ring-blue-50 transition-all uppercase"
                value={formData.catName}
                onChange={(e) => setFormData({...formData, catName: e.target.value.toUpperCase()})}
              />
            </div>
          </div>

          {/* Features Checkboxes */}
          <div className="p-8 bg-slate-50 rounded-[32px] border border-slate-100">
            <label className="text-[10px] font-black uppercase text-slate-500 tracking-widest mb-6 block">Enable Content Sections</label>
            <div className="grid grid-cols-2 lg:grid-cols-5 gap-4">
              {featureOptions.map(f => (
                <button
                  key={f}
                  type="button"
                  onClick={() => toggleFeature(f)}
                  className={`flex items-center justify-center gap-3 p-4 rounded-2xl border-2 transition-all font-black text-[10px] ${
                    formData.features.includes(f) 
                    ? "bg-blue-600 border-blue-600 text-white shadow-xl shadow-blue-100" 
                    : "bg-white border-slate-200 text-slate-400 hover:border-blue-200"
                  }`}
                >
                  {formData.features.includes(f) ? <CheckSquare size={16} /> : <Square size={16} />}
                  {f}
                </button>
              ))}
            </div>
          </div>

          <button 
            disabled={isSaving}
            className="w-full py-5 bg-[#0F172A] hover:bg-blue-600 text-white rounded-[22px] font-black text-xs uppercase tracking-[0.3em] shadow-2xl transition-all active:scale-95 flex items-center justify-center gap-4"
          >
            {isSaving ? <Loader2 className="animate-spin" /> : <Save size={20} />}
            {editId ? "Update Category Record" : "Save Category Master"}
          </button>
        </form>
      </section>

      {/* --- TABLE SECTION --- */}
      <section className="bg-white rounded-[40px] shadow-xl border border-slate-100 overflow-hidden">
        <div className="p-8 border-b border-slate-50 flex flex-col md:flex-row justify-between items-center gap-6">
          <h2 className="text-xl font-black uppercase text-slate-800 tracking-tighter">Existing Categories</h2>
          <div className="relative w-full md:w-80">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input 
              type="text" 
              placeholder="SEARCH BY EXAM OR NAME..."
              className="w-full pl-12 pr-6 py-3 bg-slate-50 rounded-2xl text-[10px] font-black uppercase outline-none focus:ring-2 ring-blue-100 border border-transparent focus:border-blue-200"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="bg-slate-900 text-white text-[9px] font-black uppercase tracking-[0.2em]">
                <th className="p-6">ID</th>
                <th className="p-6">Parent Exam</th>
                <th className="p-6">Category Name</th>
                <th className="p-6">Active Features</th>
                <th className="p-6 text-center">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {loading ? (
                <tr>
                  <td colSpan="5" className="p-20 text-center font-black text-slate-300 uppercase animate-pulse">
                    Syncing Master Data...
                  </td>
                </tr>
              ) : filteredCategories.length > 0 ? (
                filteredCategories.map(cat => (
                  <tr key={cat._id} className="group hover:bg-blue-50/30 transition-all">
                    <td className="p-6 text-blue-600 font-black text-xs">{cat.catId}</td>
                    <td className="p-6 font-black text-slate-400 text-[10px] uppercase">
                      {cat.examId?.examName || "---"}
                    </td>
                    <td className="p-6 font-black text-slate-800 text-sm uppercase">{cat.catName}</td>
                    <td className="p-6">
                      <div className="flex flex-wrap gap-2">
                        {cat.features.map(f => (
                          <span key={f} className="px-3 py-1 bg-blue-50 text-blue-600 rounded-lg text-[8px] font-black border border-blue-100 uppercase">
                            {f}
                          </span>
                        ))}
                      </div>
                    </td>
                    <td className="p-6 flex justify-center gap-3">
                      <button 
                        onClick={() => handleEdit(cat)}
                        className="p-3 bg-blue-50 text-blue-600 rounded-xl hover:bg-blue-600 hover:text-white transition-all shadow-sm"
                      >
                        <Edit size={16} />
                      </button>
                      <button 
                        onClick={() => handleDelete(cat._id)}
                        className="p-3 bg-red-50 text-red-500 rounded-xl hover:bg-red-500 hover:text-white transition-all shadow-sm"
                      >
                        <Trash2 size={16} />
                      </button>
                    </td>
                  </tr>
                ))
              ) : (
                <tr>
                  <td colSpan="5" className="p-20 text-center font-black text-slate-300 uppercase">
                    No matching categories found
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </section>
    </div>
  );
};

export default CategoryMaster;
